#include <iostream>
using namespace std;

// Функція обчислення факторіалу
long long factorial(int n) {
    // 1. Базовий випадок (Кінець рекурсії)
    if (n <= 1) {
        return 1;
    }
    // 2. Рекурсивний крок
    // (Позначили зірочку. Будемо чекати поки return не поверне результат)
    return n * factorial(n - 1);
}

// Функція зворотного відліку
void countdown(int t) {
    if (t <= 0) {
        cout << "Пуск РАКЕТИ!" << endl;
        return; // Гальма. Завершуємо цю гілку.
    }
    cout << "До старту: " << t << "..." << endl;

    // Викликаємо саму себе зі зменшеним значенням
    countdown(t - 1);
}

int main() {
    cout << "Рахуємо 5! (Факторіал): " << factorial(5) << endl;

    cout << "
==== Запуск ====" << endl;
    countdown(3);

    return 0;
}
